23: // The base class of the stream listener. It owns listener filter handling of active sockets.
24: // After the active socket passes all the listener filters, a server connection is created. The
25: // derived listener must override ``newActiveConnection`` to take the ownership of that server
26: // connection.
27: // TODO(lambdai): Refactor the listener filter test cases to adopt this class.
28: class ActiveStreamListenerBase : public ActiveListenerImplBase,
29:                                  protected Logger::Loggable<Logger::Id::conn_handler> {
30: public:
31:   ActiveStreamListenerBase(Network::ConnectionHandler& parent, Event::Dispatcher& dispatcher,
32:                            Network::ListenerPtr&& listener, Network::ListenerConfig& config);
33:   static void emitLogs(Network::ListenerConfig& config, StreamInfo::StreamInfo& stream_info);
34: 
35:   Event::Dispatcher& dispatcher() { return dispatcher_; }
36: 
37:   /**
38:    * Schedule to remove and destroy the active connections which are not tracked by listener
39:    * config. Caution: The connection are not destroyed yet when function returns.
40:    */
41:   void onFilterChainDraining(
42:       const std::list<const Network::FilterChain*>& draining_filter_chains) override {
43:     // Need to recover the original deleting state.
44:     const bool was_deleting = is_deleting_;
45:     is_deleting_ = true;
46:     for (const auto* filter_chain : draining_filter_chains) {
47:       removeFilterChain(filter_chain);
48:     }
49:     is_deleting_ = was_deleting;
50:   }
51: 
52:   virtual void incNumConnections() PURE;
53:   virtual void decNumConnections() PURE;
54: 
55:   /**
56:    * Create a new connection from a socket accepted by the listener.
57:    */
58:   void newConnection(Network::ConnectionSocketPtr&& socket,
59:                      std::unique_ptr<StreamInfo::StreamInfo> stream_info);
60: 
61:   /**
62:    * Remove the socket from this listener. Should be called when the socket passes the listener
63:    * filter.
64:    * @return std::unique_ptr<ActiveTcpSocket> the exact same socket in the parameter but in the
65:    * state that not owned by the listener.
66:    */
67:   std::unique_ptr<ActiveTcpSocket> removeSocket(ActiveTcpSocket&& socket) {
68:     return socket.removeFromList(sockets_);
69:   }
70: 
71:   /**
72:    * @return const std::list<std::unique_ptr<ActiveTcpSocket>>& the sockets going through the
73:    * listener filters.
74:    */
75:   const std::list<std::unique_ptr<ActiveTcpSocket>>& sockets() const { return sockets_; }
76: 
77:   /**
78:    * Schedule removal and destruction of all active connections owned by a filter chain.
79:    */
80:   virtual void removeFilterChain(const Network::FilterChain* filter_chain) PURE;
81: 
82:   virtual Network::BalancedConnectionHandlerOptRef
83:   getBalancedHandlerByAddress(const Network::Address::Instance& address) PURE;
84: 
85:   void onSocketAccepted(std::unique_ptr<ActiveTcpSocket> active_socket) {
86:     // Create and run the filters
87:     if (config_->filterChainFactory().createListenerFilterChain(*active_socket)) {
88:       active_socket->startFilterChain();
89:     } else {
90:       // If create listener filter chain failed, it means the listener is missing
91:       // config due to the ECDS. Then close the connection directly.
92:       active_socket->socket().close();
93:       ASSERT(active_socket->isEndFilterIteration());
94:     }
95: 
96:     // Move active_socket to the sockets_ list if filter iteration needs to continue later.
97:     // Otherwise we let active_socket be destructed when it goes out of scope.
98:     if (!active_socket->isEndFilterIteration()) {
99:       active_socket->startTimer();
100:       LinkedList::moveIntoListBack(std::move(active_socket), sockets_);
101:     } else {
102:       if (!active_socket->connected()) {
103:         // If active_socket is about to be destructed, emit logs if a connection is not created.
104:         if (active_socket->streamInfo() != nullptr) {
105:           emitLogs(*config_, *active_socket->streamInfo());
106:         } else {
107:           // If the active_socket is not connected, this socket is not promoted to active
108:           // connection. Thus the stream_info_ is owned by this active socket.
109:           ENVOY_BUG(active_socket->streamInfo() != nullptr,
110:                     "the unconnected active socket must have stream info.");
111:         }
112:       }
113:     }
114:   }
115: 
116:   // Below members are open to access by ActiveTcpSocket.
117:   Network::ConnectionHandler& parent_;
118:   const std::chrono::milliseconds listener_filters_timeout_;
119:   const bool continue_on_listener_filters_timeout_;
120: 
121: protected:
122:   /**
123:    * Create the active connection from server connection. This active listener owns the created
124:    * active connection.
125:    *
126:    * @param filter_chain The network filter chain linking to the connection.
127:    * @param server_conn_ptr The server connection.
128:    * @param stream_info The stream info of the active connection.
129:    */
130:   virtual void newActiveConnection(const Network::FilterChain& filter_chain,
131:                                    Network::ServerConnectionPtr server_conn_ptr,
132:                                    std::unique_ptr<StreamInfo::StreamInfo> stream_info) PURE;
133: 
134:   std::list<std::unique_ptr<ActiveTcpSocket>> sockets_;
135:   Network::ListenerPtr listener_;
136:   // True if the follow up connection deletion is raised by the connection collection deletion is
137:   // performing. Otherwise, the collection should be deleted when the last connection in the
138:   // collection is removed. This state is maintained in base class because this state is independent
139:   // from concrete connection type.
140:   bool is_deleting_{false};
141: 
142: private:
143:   Event::Dispatcher& dispatcher_;
144: };
