51: // This is the last stop in the filter chain: take the headers and ship them to the codec.
52: Http::FilterHeadersStatus UpstreamCodecFilter::decodeHeaders(Http::RequestHeaderMap& headers,
53:                                                              bool end_stream) {
54:   ASSERT(callbacks_->upstreamCallbacks());
55:   if (!callbacks_->upstreamCallbacks()->upstream()) {
56:     latched_headers_ = headers;
57:     latched_end_stream_ = end_stream;
58:     return Http::FilterHeadersStatus::StopAllIterationAndWatermark;
59:   }
60: 
61:   ENVOY_STREAM_LOG(trace, "proxying headers", *callbacks_);
62:   calling_encode_headers_ = true;
63:   const Http::Status status =
64:       callbacks_->upstreamCallbacks()->upstream()->encodeHeaders(headers, end_stream);
65: 
66:   calling_encode_headers_ = false;
67:   if (!status.ok() || !deferred_reset_status_.ok()) {
68:     // It is possible that encodeHeaders() fails. This can happen if filters or other extensions
69:     // erroneously remove required headers.
70:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::DownstreamProtocolError);
71:     const std::string details =
72:         deferred_reset_status_.ok()
73:             ? absl::StrCat(
74:                   StreamInfo::ResponseCodeDetails::get().FilterRemovedRequiredRequestHeaders, "{",
75:                   StringUtil::replaceAllEmptySpace(status.message()), "}")
76:             : absl::StrCat(StreamInfo::ResponseCodeDetails::get().EarlyUpstreamReset, "{",
77:                            StringUtil::replaceAllEmptySpace(deferred_reset_status_.message()), "}");
78:     deferred_reset_status_ = absl::OkStatus();
79:     callbacks_->sendLocalReply(Http::Code::ServiceUnavailable, status.message(), nullptr,
80:                                absl::nullopt, details);
81:     return Http::FilterHeadersStatus::StopIteration;
82:   }
83:   upstreamTiming().onFirstUpstreamTxByteSent(callbacks_->dispatcher().timeSource());
84: 
85:   if (end_stream) {
86:     upstreamTiming().onLastUpstreamTxByteSent(callbacks_->dispatcher().timeSource());
87:   }
88:   if (callbacks_->upstreamCallbacks()->pausedForConnect()) {
89:     return Http::FilterHeadersStatus::StopAllIterationAndWatermark;
90:   } else if (callbacks_->upstreamCallbacks()->pausedForWebsocketUpgrade()) {
91:     return Http::FilterHeadersStatus::StopAllIterationAndWatermark;
92:   }
93:   return Http::FilterHeadersStatus::Continue;
94: }
