544: Network::FilterStatus ConnectionManagerImpl::onNewConnection() {
545:   if (!read_callbacks_->connection().streamInfo().protocol()) {
546:     // For Non-QUIC traffic, continue passing data to filters.
547:     return Network::FilterStatus::Continue;
548:   }
549:   // Only QUIC connection's stream_info_ specifies protocol.
550:   Buffer::OwnedImpl dummy;
551:   createCodec(dummy);
552:   ASSERT(codec_->protocol() == Protocol::Http3);
553:   // Stop iterating through network filters for QUIC. Currently QUIC connections bypass the
554:   // onData() interface because QUICHE already handles de-multiplexing.
555:   return Network::FilterStatus::StopIteration;
556: }
